// Solution.cpp
#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

class Solution {
public:
    int solve(int n, int k, vector<pair<int, int>>& events) {
        sort(events.begin(), events.end(), [](const pair<int, int>& a, const pair<int, int>& b) {
            return a.second < b.second;
        });
        int max_duration = 0;
        int subintervals = 0;
        for (auto& event : events) {
            if (subintervals < k && event.first >= events[subintervals - 1].second) {
                max_duration += event.second - event.first;
                subintervals++;
            }
        }
        return max_duration;
    }
};
